Add the PINNED_AGENTS localStorage key constant and implement pinnedAgentPaths state with pinAgent/unpinAgent actions in the CoreSlice of the Zustand app store.

## Files to modify

### 1. `apps/client/src/layers/shared/lib/constants.ts`

Add `PINNED_AGENTS` to the existing `STORAGE_KEYS` object:

```typescript
export const STORAGE_KEYS = {
  FONT_SIZE: 'dorkos-font-size',
  FONT_FAMILY: 'dorkos-font-family',
  RECENT_CWDS: 'dorkos-recent-cwds',
  PICKER_VIEW: 'dorkos-picker-view',
  GESTURE_HINT_COUNT: 'dorkos-gesture-hint-count',
  CANVAS_SESSIONS: 'dorkos-canvas-sessions',
  PINNED_AGENTS: 'dorkos-pinned-agents',
} as const;
```

### 2. `apps/client/src/layers/shared/model/app-store/app-store-types.ts`

Extend the `CoreSlice` interface with three new members:

```typescript
export interface CoreSlice {
  // ... existing fields ...

  /** Ordered list of agent paths pinned by the user. Persisted to localStorage. */
  pinnedAgentPaths: string[];
  /** Pin an agent. Appends to end of pinned list if not already pinned. */
  pinAgent: (path: string) => void;
  /** Remove an agent from the pinned list. No-op if not pinned. */
  unpinAgent: (path: string) => void;
}
```

### 3. `apps/client/src/layers/shared/model/app-store/app-store.ts`

Add the initializer and two actions inside the `create<AppState>()` call, in the core slice section. The initializer reads from localStorage with defensive parsing (same pattern as `recentCwds`):

```typescript
pinnedAgentPaths: (() => {
  try {
    const raw: unknown = JSON.parse(
      localStorage.getItem(STORAGE_KEYS.PINNED_AGENTS) || '[]'
    );
    return Array.isArray(raw) ? (raw as string[]).filter((v) => typeof v === 'string') : [];
  } catch {
    return [];
  }
})(),

pinAgent: (path) =>
  set((s) => {
    if (s.pinnedAgentPaths.includes(path)) return s;
    const next = [...s.pinnedAgentPaths, path];
    try { localStorage.setItem(STORAGE_KEYS.PINNED_AGENTS, JSON.stringify(next)); } catch {}
    return { pinnedAgentPaths: next };
  }),

unpinAgent: (path) =>
  set((s) => {
    const next = s.pinnedAgentPaths.filter((p) => p !== path);
    try { localStorage.setItem(STORAGE_KEYS.PINNED_AGENTS, JSON.stringify(next)); } catch {}
    return { pinnedAgentPaths: next };
  }),
```

Also update the `resetPreferences` action to clear pin state:

```typescript
resetPreferences: () => {
  try {
    // ... existing localStorage.removeItem calls ...
    localStorage.removeItem(STORAGE_KEYS.PINNED_AGENTS);
  } catch {}
  // ... existing set() call — add pinnedAgentPaths: [] to the reset object ...
  set({
    ...BOOL_DEFAULTS,
    // ... existing reset fields ...
    pinnedAgentPaths: [],
  });
},
```

Note: `STORAGE_KEYS` is already imported in app-store.ts from `@/layers/shared/lib`.

## Tests

Create `apps/client/src/layers/shared/model/app-store/__tests__/app-store-pin.test.ts`:

```typescript
import { describe, it, expect, beforeEach, vi } from 'vitest';
import { useAppStore } from '../app-store';
import { STORAGE_KEYS } from '@/layers/shared/lib/constants';

describe('pinnedAgentPaths store', () => {
  beforeEach(() => {
    localStorage.clear();
    // Reset the store to initial state
    useAppStore.setState({ pinnedAgentPaths: [] });
  });

  it('pinAgent adds path and persists to localStorage', () => {
    useAppStore.getState().pinAgent('/agents/alpha');
    expect(useAppStore.getState().pinnedAgentPaths).toEqual(['/agents/alpha']);
    expect(JSON.parse(localStorage.getItem(STORAGE_KEYS.PINNED_AGENTS)!)).toEqual(['/agents/alpha']);
  });

  it('pinAgent appends to end preserving order', () => {
    useAppStore.getState().pinAgent('/agents/alpha');
    useAppStore.getState().pinAgent('/agents/beta');
    expect(useAppStore.getState().pinnedAgentPaths).toEqual(['/agents/alpha', '/agents/beta']);
  });

  it('pinAgent is idempotent — no duplicates', () => {
    useAppStore.getState().pinAgent('/agents/alpha');
    useAppStore.getState().pinAgent('/agents/alpha');
    expect(useAppStore.getState().pinnedAgentPaths).toEqual(['/agents/alpha']);
  });

  it('unpinAgent removes path and persists', () => {
    useAppStore.getState().pinAgent('/agents/alpha');
    useAppStore.getState().pinAgent('/agents/beta');
    useAppStore.getState().unpinAgent('/agents/alpha');
    expect(useAppStore.getState().pinnedAgentPaths).toEqual(['/agents/beta']);
    expect(JSON.parse(localStorage.getItem(STORAGE_KEYS.PINNED_AGENTS)!)).toEqual(['/agents/beta']);
  });

  it('unpinAgent is no-op for unknown paths', () => {
    useAppStore.getState().pinAgent('/agents/alpha');
    useAppStore.getState().unpinAgent('/agents/unknown');
    expect(useAppStore.getState().pinnedAgentPaths).toEqual(['/agents/alpha']);
  });

  it('resetPreferences clears pin state', () => {
    useAppStore.getState().pinAgent('/agents/alpha');
    useAppStore.getState().resetPreferences();
    expect(useAppStore.getState().pinnedAgentPaths).toEqual([]);
    expect(localStorage.getItem(STORAGE_KEYS.PINNED_AGENTS)).toBeNull();
  });

  it('hydrates from localStorage on store creation', () => {
    localStorage.setItem(STORAGE_KEYS.PINNED_AGENTS, JSON.stringify(['/agents/persisted']));
    // Re-import or reset to trigger hydration logic — for Zustand, setState to simulate
    // In practice, the initializer runs at module load time. This test verifies the parsing logic.
    const raw = JSON.parse(localStorage.getItem(STORAGE_KEYS.PINNED_AGENTS) || '[]');
    const parsed = Array.isArray(raw) ? raw.filter((v: unknown) => typeof v === 'string') : [];
    expect(parsed).toEqual(['/agents/persisted']);
  });

  it('falls back to [] when localStorage contains corrupt data', () => {
    localStorage.setItem(STORAGE_KEYS.PINNED_AGENTS, 'not-json');
    let result: string[];
    try {
      const raw: unknown = JSON.parse(localStorage.getItem(STORAGE_KEYS.PINNED_AGENTS) || '[]');
      result = Array.isArray(raw) ? (raw as string[]).filter((v) => typeof v === 'string') : [];
    } catch {
      result = [];
    }
    expect(result).toEqual([]);
  });

  it('filters non-string values from localStorage', () => {
    localStorage.setItem(STORAGE_KEYS.PINNED_AGENTS, JSON.stringify(['/valid', 42, null, '/also-valid']));
    const raw: unknown = JSON.parse(localStorage.getItem(STORAGE_KEYS.PINNED_AGENTS)!);
    const parsed = Array.isArray(raw) ? (raw as unknown[]).filter((v): v is string => typeof v === 'string') : [];
    expect(parsed).toEqual(['/valid', '/also-valid']);
  });
});
```

## Acceptance criteria

1. `STORAGE_KEYS.PINNED_AGENTS` exists and equals `'dorkos-pinned-agents'`
2. `pinnedAgentPaths` initializes from localStorage with defensive parsing
3. `pinAgent` appends to list, is idempotent, and persists to localStorage
4. `unpinAgent` removes from list (no-op if absent) and persists
5. `resetPreferences` clears `pinnedAgentPaths` to `[]` and removes the localStorage key
6. Corrupt or non-array localStorage values fall back to `[]`
7. All tests pass

Rewrite DashboardSidebar.tsx to replace the LRU-ordered, capped agent list with a full alphabetical roster sourced from `useMeshAgentPaths()`. Implement the two-section layout (Pinned + All) and auto-pin the default agent on first install.

## Files to modify

### `apps/client/src/layers/features/dashboard-sidebar/ui/DashboardSidebar.tsx`

Major changes:

1. **Remove `MAX_AGENTS` constant** entirely (line 23 currently).

2. **Import `useMeshAgentPaths`** from `@/layers/entities/mesh` instead of relying on `recentCwds`.

3. **Import pin state** from the app store: `pinnedAgentPaths`, `pinAgent`, `unpinAgent`.

4. **Replace `agentPaths` memo** with two new memos:

```typescript
const { data: meshPaths } = useMeshAgentPaths();

const allPaths = useMemo(() => {
  const paths = meshPaths ?? [];
  return [...paths].sort((a, b) => {
    const nameA = a.split('/').pop()?.toLowerCase() ?? '';
    const nameB = b.split('/').pop()?.toLowerCase() ?? '';
    return nameA.localeCompare(nameB);
  });
}, [meshPaths]);

const pinnedPaths = useMemo(() => {
  const pathSet = new Set(allPaths);
  return pinnedAgentPaths.filter((p) => pathSet.has(p));
}, [pinnedAgentPaths, allPaths]);
```

5. **Update `displayNames` memo** to use `allPaths` instead of `agentPaths`.

6. **Update `useResolvedAgents` call** to use `allPaths` instead of `agentPaths`.

7. **Auto-pin default agent on first install** — a one-time effect that runs when the store has no pins yet and the default agent path is known:

```typescript
const pinAgent = useAppStore((s) => s.pinAgent);
const pinnedAgentPaths = useAppStore((s) => s.pinnedAgentPaths);

useEffect(() => {
  if (pinnedAgentPaths.length === 0 && defaultAgentPath && allPaths.includes(defaultAgentPath)) {
    pinAgent(defaultAgentPath);
  }
}, [pinnedAgentPaths.length, defaultAgentPath, allPaths, pinAgent]);
```

8. **Render two-section layout** in the return JSX:

```tsx
<SidebarContent className="p-3">
  <SidebarGroup>
    <SidebarGroupLabel className="text-muted-foreground/70 text-[10px] font-medium tracking-wider uppercase">
      Agents
    </SidebarGroupLabel>

    {/* Pinned section — only if pins exist */}
    {pinnedPaths.length > 0 && (
      <>
        <SidebarGroupLabel className="text-muted-foreground/50 mt-1 text-[9px] font-medium tracking-wider uppercase">
          Pinned
        </SidebarGroupLabel>
        <SidebarMenu>
          {pinnedPaths.map((path) => {
            const isActive = selectedCwd === path;
            return (
              <AgentListItem
                key={`pinned-${path}`}
                path={path}
                agent={agents?.[path] ?? null}
                displayName={displayNames.get(path)}
                isActive={isActive}
                isExpanded={expandedPath === path}
                isPinned={true}
                onSelect={() => handleSelectAgent(path)}
                onToggleExpand={() => handleToggleExpand(path)}
                onTogglePin={() => handleTogglePin(path)}
                onManage={() => handleManage(path)}
                onEditSettings={() => handleEditSettings()}
                sessions={isActive ? previewSessions : []}
                totalSessionCount={isActive ? sessions.length : 0}
                activeSessionId={activeSessionId}
                onSessionClick={handleSessionClick}
                onNewSession={handleNewSession}
                onDrillIntoSessions={handleDrillIntoSessions}
              />
            );
          })}
        </SidebarMenu>
      </>
    )}

    {/* All agents — alphabetical */}
    <SidebarMenu>
      {allPaths.map((path) => {
        const isActive = selectedCwd === path;
        return (
          <AgentListItem
            key={path}
            path={path}
            agent={agents?.[path] ?? null}
            displayName={displayNames.get(path)}
            isActive={isActive}
            isExpanded={expandedPath === path}
            isPinned={pinnedAgentPaths.includes(path)}
            onSelect={() => handleSelectAgent(path)}
            onToggleExpand={() => handleToggleExpand(path)}
            onTogglePin={() => handleTogglePin(path)}
            onManage={() => handleManage(path)}
            onEditSettings={() => handleEditSettings()}
            sessions={isActive ? previewSessions : []}
            totalSessionCount={isActive ? sessions.length : 0}
            activeSessionId={activeSessionId}
            onSessionClick={handleSessionClick}
            onNewSession={handleNewSession}
            onDrillIntoSessions={handleDrillIntoSessions}
          />
        );
      })}
    </SidebarMenu>
  </SidebarGroup>
  <PromoSlot placement="dashboard-sidebar" maxUnits={3} />
</SidebarContent>
```

9. **Add new handlers** for the new props:

```typescript
const unpinAgent = useAppStore((s) => s.unpinAgent);
const setAgentDialogOpen = useAppStore((s) => s.setAgentDialogOpen);

const handleTogglePin = useCallback(
  (path: string) => {
    if (pinnedAgentPaths.includes(path)) {
      unpinAgent(path);
    } else {
      pinAgent(path);
    }
  },
  [pinnedAgentPaths, pinAgent, unpinAgent]
);

const handleManage = useCallback(
  (path: string) => {
    navigate({ to: '/session', search: { dir: path } });
    setSidebarLevel('session');
  },
  [navigate, setSidebarLevel]
);

const handleEditSettings = useCallback(() => {
  setAgentDialogOpen(true);
}, [setAgentDialogOpen]);
```

10. **Keep all existing behavior**: SidebarHeader navigation, Search button, expand/collapse tracking, session preview, session click, PromoSlot.

